const env = (typeof $env === 'object' && $env)
  ? $env
  : (typeof process !== 'undefined' && process.env ? process.env : {});

const requiredVars = [
  'DB_BACKUP_TARGETS_JSON',
  'DB_BACKUP_LOCAL_DIR',
  'DB_BACKUP_DRIVE_REMOTE',
  'DB_BACKUP_DRIVE_FOLDER',
];

const missingVars = requiredVars.filter((key) => !String(env[key] || '').trim());
if (missingVars.length > 0) {
  throw new Error(`Variaveis obrigatorias ausentes: ${missingVars.join(', ')}`);
}

let targets;
try {
  targets = JSON.parse(env.DB_BACKUP_TARGETS_JSON);
} catch (error) {
  throw new Error(`DB_BACKUP_TARGETS_JSON invalido: ${error.message}`);
}

if (!Array.isArray(targets) || targets.length === 0) {
  throw new Error('DB_BACKUP_TARGETS_JSON deve conter ao menos um banco');
}

const enabledTargets = targets.filter((target) => target && target.enabled !== false);
if (enabledTargets.length === 0) {
  throw new Error('Nenhum banco habilitado em DB_BACKUP_TARGETS_JSON');
}

const toPositiveInt = (value, fallback) => {
  const parsed = Number.parseInt(String(value ?? ''), 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
};

const config = {
  timezone: String(env.DB_BACKUP_TIMEZONE || env.GENERIC_TIMEZONE || 'America/Sao_Paulo'),
  local_dir: String(env.DB_BACKUP_LOCAL_DIR),
  drive_remote: String(env.DB_BACKUP_DRIVE_REMOTE),
  drive_folder: String(env.DB_BACKUP_DRIVE_FOLDER),
  local_retention_days: toPositiveInt(env.DB_BACKUP_LOCAL_RETENTION_DAYS, 7),
  drive_retention_days: toPositiveInt(env.DB_BACKUP_DRIVE_RETENTION_DAYS, 30),
  targets: enabledTargets,
};

const configB64 = Buffer.from(JSON.stringify(config), 'utf8').toString('base64');
const command = `python3 - <<'PY'
import base64
import json
import os
import re
import shlex
import shutil
import subprocess
from datetime import datetime, timezone

CONFIG = json.loads(base64.b64decode('${configB64}').decode('utf-8'))


def sanitize_name(value):
    safe = re.sub(r'[^A-Za-z0-9._-]+', '-', str(value or '').strip())
    safe = safe.strip('.-')
    return safe or 'database'


def run_command(command, env=None):
    result = subprocess.run(
        ['bash', '-lc', command],
        capture_output=True,
        text=True,
        env=env,
        check=False,
    )
    if result.returncode != 0:
        raise RuntimeError((result.stderr or result.stdout or 'command failed').strip())
    return result


def quote(value):
    return shlex.quote(str(value))


def ensure_tool(tool_name):
    if shutil.which(tool_name) is None:
        raise RuntimeError(f'Ferramenta obrigatoria ausente no host remoto: {tool_name}')


for base_tool in ['bash', 'find', 'gzip', 'python3', 'rclone']:
    ensure_tool(base_tool)

summary = {
    'startedAt': datetime.now(timezone.utc).isoformat().replace('+00:00', 'Z'),
    'timezone': CONFIG['timezone'],
    'localRetentionDays': CONFIG['local_retention_days'],
    'driveRetentionDays': CONFIG['drive_retention_days'],
    'driveFolder': CONFIG['drive_folder'],
    'driveRemote': CONFIG['drive_remote'],
    'successCount': 0,
    'failureCount': 0,
    'backups': [],
    'failures': [],
}

for raw_target in CONFIG['targets']:
    target = dict(raw_target)
    name = sanitize_name(target.get('name'))
    db_type = str(target.get('type') or '').strip().lower()
    target_local_root = os.path.join(CONFIG['local_dir'], name)
    target_remote_root = f"{CONFIG['drive_remote']}:{CONFIG['drive_folder'].strip('/')}/{name}"
    execution_dt = datetime.now(timezone.utc)
    date_path = execution_dt.strftime('%Y/%m/%d')
    time_dir = execution_dt.strftime('%H%M%SZ')
    timestamp = execution_dt.strftime('%Y%m%dT%H%M%SZ')
    local_dir = os.path.join(target_local_root, *date_path.split('/'), time_dir)
    remote_dir = f"{target_remote_root}/{date_path}/{time_dir}"

    try:
        if db_type not in {'postgres', 'mysql', 'mongodb'}:
            raise RuntimeError(f"Tipo de banco nao suportado: {db_type}")

        if db_type == 'postgres':
            ensure_tool('pg_dump')
            database = target.get('database')
            username = target.get('username')
            password = target.get('password', '')
            host = target.get('host', '127.0.0.1')
            port = int(target.get('port', 5432))
            extra_args = str(target.get('extra_args') or '')
            if not database or not username:
                raise RuntimeError('Postgres exige database e username')
            filename = f"{name}_{timestamp}.dump"
            local_path = os.path.join(local_dir, filename)
            env = os.environ.copy()
            env['PGPASSWORD'] = str(password)
            cmd = [
                'pg_dump',
                '--host', str(host),
                '--port', str(port),
                '--username', str(username),
                '--dbname', str(database),
                '--format=custom',
                '--compress=9',
                '--no-password',
                '--file', local_path,
            ]
            if extra_args:
                cmd.extend(shlex.split(extra_args))
            backup_command = ' '.join(quote(part) for part in cmd)
        elif db_type == 'mysql':
            ensure_tool('mysqldump')
            database = target.get('database')
            username = target.get('username')
            password = target.get('password', '')
            host = target.get('host', '127.0.0.1')
            port = int(target.get('port', 3306))
            extra_args = str(target.get('extra_args') or '')
            if not database or not username:
                raise RuntimeError('MySQL exige database e username')
            filename = f"{name}_{timestamp}.sql.gz"
            local_path = os.path.join(local_dir, filename)
            cmd = [
                'mysqldump',
                '--host', str(host),
                '--port', str(port),
                '--user', str(username),
                '--single-transaction',
                '--quick',
                '--routines',
                '--events',
                '--triggers',
                str(database),
            ]
            if extra_args:
                cmd.extend(shlex.split(extra_args))
            backup_command = f"MYSQL_PWD={quote(password)} {' '.join(quote(part) for part in cmd)} | gzip -9 > {quote(local_path)}"
        else:
            ensure_tool('mongodump')
            database = target.get('database')
            extra_args = str(target.get('extra_args') or '')
            filename = f"{name}_{timestamp}.archive.gz"
            local_path = os.path.join(local_dir, filename)
            connection_uri = str(target.get('connection_uri') or '').strip()
            auth_database = str(target.get('auth_database') or 'admin')
            if connection_uri:
                cmd = ['mongodump', f'--uri={connection_uri}']
                if database:
                    cmd.extend(['--db', str(database)])
            else:
                username = target.get('username')
                password = target.get('password', '')
                host = target.get('host', '127.0.0.1')
                port = int(target.get('port', 27017))
                if not database or not username:
                    raise RuntimeError('MongoDB exige connection_uri ou database e username')
                cmd = [
                    'mongodump',
                    '--host', str(host),
                    '--port', str(port),
                    '--username', str(username),
                    '--password', str(password),
                    '--authenticationDatabase', auth_database,
                    '--db', str(database),
                ]
            if extra_args:
                cmd.extend(shlex.split(extra_args))
            cmd.append('--archive')
            backup_command = f"{' '.join(quote(part) for part in cmd)} | gzip -9 > {quote(local_path)}"

        os.makedirs(local_dir, exist_ok=True)
        run_command(f"mkdir -p {quote(local_dir)}")
        run_command(f"rclone mkdir {quote(remote_dir)}")
        run_command(backup_command, env=env if db_type == 'postgres' else None)
        run_command(f"rclone copyto {quote(local_path)} {quote(remote_dir + '/' + filename)}")
        run_command(f"find {quote(target_local_root)} -type f -mtime +{int(CONFIG['local_retention_days'])} -delete")
        run_command(f"find {quote(target_local_root)} -depth -type d -empty -delete")
        run_command(f"rclone delete {quote(target_remote_root)} --min-age {int(CONFIG['drive_retention_days'])}d")
        run_command(f"rclone rmdirs {quote(target_remote_root)}")

        file_size_bytes = os.path.getsize(local_path)
        summary['successCount'] += 1
        summary['backups'].append({
            'name': name,
            'type': db_type,
            'filename': filename,
            'localPath': local_path,
            'remotePath': f"{remote_dir}/{filename}",
            'sizeBytes': file_size_bytes,
            'finishedAt': datetime.now(timezone.utc).isoformat().replace('+00:00', 'Z'),
        })
    except Exception as exc:
        summary['failureCount'] += 1
        summary['failures'].append({
            'name': name,
            'type': db_type,
            'error': str(exc),
            'failedAt': datetime.now(timezone.utc).isoformat().replace('+00:00', 'Z'),
        })

summary['finishedAt'] = datetime.now(timezone.utc).isoformat().replace('+00:00', 'Z')
print(json.dumps(summary, ensure_ascii=True))
PY`;

return [{
  json: {
    command,
    configSummary: {
      timezone: config.timezone,
      localRetentionDays: config.local_retention_days,
      driveRetentionDays: config.drive_retention_days,
      driveFolder: config.drive_folder,
      targetNames: enabledTargets.map((target) => String(target.name || 'database')),
      targetCount: enabledTargets.length,
    },
  },
}];

const stdout = String(items[0]?.json?.stdout ?? items[0]?.json?.data ?? '').trim();
const stderr = String(items[0]?.json?.stderr ?? items[0]?.json?.error ?? '').trim();
const exitCode = items[0]?.json?.exitCode ?? items[0]?.json?.code ?? null;

if (!stdout) {
  const diagnostics = [
    exitCode !== null ? `exitCode=${exitCode}` : '',
    stderr ? `stderr=${stderr}` : '',
  ].filter(Boolean).join(' | ');
  throw new Error(`O host remoto nao retornou resumo do backup${diagnostics ? `: ${diagnostics}` : ''}`);
}

let summary;
try {
  summary = JSON.parse(stdout);
} catch (error) {
  const preview = stdout.slice(0, 500);
  throw new Error(`Resumo de backup invalido: ${error.message}. Saida recebida: ${preview}`);
}

summary.hadFailures = Number(summary.failureCount || 0) > 0;
summary.message = [
  `Backups executados: ${summary.successCount || 0}`,
  `Falhas: ${summary.failureCount || 0}`,
  `Retencao local: ${summary.localRetentionDays || 'n/d'} dia(s)`,
  `Retencao Drive: ${summary.driveRetentionDays || 'n/d'} dia(s)`,
].join(' | ');

if (summary.hadFailures) {
  const failedTargets = Array.isArray(summary.failures)
    ? summary.failures.map((item) => `${item.name}: ${item.error}`).join('; ')
    : 'falhas nao detalhadas';
  throw new Error(`Backup concluido com falhas. ${failedTargets}`);
}

return [{ json: summary }];
